title: Declare All Dependencies Explicitly in Constructor
impact: HIGH
impactDescription: enables testing, documents requirements, prevents hidden coupling
tags: usecase, dependencies, constructor, injection
---

## Declare All Dependencies Explicitly in Constructor

Use cases should receive all dependencies through their constructor. Hidden dependencies (service locators, singletons, static calls) make testing difficult and hide coupling.

**Incorrect (hidden dependencies):**

```java
public class PlaceOrderUseCase {
    public OrderConfirmation execute(PlaceOrderCommand command) {
        // Hidden dependencies - impossible to test or trace
        var customer = CustomerRepository.getInstance().find(command.customerId());
        var inventory = InventoryService.getInventory();

        for (var item : command.items()) {
            if (!inventory.isAvailable(item)) {
                throw new OutOfStockException(item);
            }
        }

        var order = new Order(customer, command.items());

        // More hidden dependencies
        Database.getConnection().save(order);
        EmailService.send(customer.email(), "Order placed");
        EventBus.publish(new OrderPlacedEvent(order));

        return new OrderConfirmation(order.id());
    }
}

// Testing requires mocking static methods - complex and brittle
```

**Correct (explicit constructor dependencies):**

```java
public class PlaceOrderUseCase {
    private final CustomerRepository customers;
    private final InventoryChecker inventory;
    private final OrderRepository orders;
    private final NotificationPort notifications;
    private final EventPublisher events;

    public PlaceOrderUseCase(
        CustomerRepository customers,
        InventoryChecker inventory,
        OrderRepository orders,
        NotificationPort notifications,
        EventPublisher events
    ) {
        this.customers = customers;
        this.inventory = inventory;
        this.orders = orders;
        this.notifications = notifications;
        this.events = events;
    }

    public OrderConfirmation execute(PlaceOrderCommand command) {
        var customer = customers.find(command.customerId());

        for (var item : command.items()) {
            if (!inventory.isAvailable(item)) {
                throw new OutOfStockException(item);
            }
        }

        var order = new Order(customer, command.items());
        orders.save(order);

        notifications.orderPlaced(customer, order);
        events.publish(new OrderPlacedEvent(order));

        return new OrderConfirmation(order.id());
    }
}

// Testing is straightforward
@Test
void placesOrderWhenInventoryAvailable() {
    var customers = mock(CustomerRepository.class);
    var inventory = mock(InventoryChecker.class);
    var orders = mock(OrderRepository.class);
    // ... configure mocks

    var useCase = new PlaceOrderUseCase(customers, inventory, orders, ...);
    var result = useCase.execute(command);

    verify(orders).save(any(Order.class));
}
```

**Benefits:**
- Dependencies visible in constructor signature
- Tests substitute any dependency with test doubles
- Coupling is explicit and measurable

Reference: [Dependency Injection Principles](https://martinfowler.com/articles/injection.html)

---
title: Define Input and Output Ports for Use Cases
impact: HIGH
impactDescription: decouples use cases from delivery mechanism
tags: usecase, ports, input, output, boundaries
---

## Define Input and Output Ports for Use Cases

Use cases should define their own input (request) and output (response) data structures. These ports isolate the use case from the delivery mechanism (HTTP, CLI, queue).

**Incorrect (use case coupled to HTTP):**

```csharp
public class RegisterUserUseCase
{
    public IActionResult Execute(HttpRequest request)  // Coupled to ASP.NET
    {
        var email = request.Form["email"];
        var password = request.Form["password"];

        if (string.IsNullOrEmpty(email))
            return new BadRequestResult();  // HTTP-specific response

        var user = new User(email, password);
        _repository.Save(user);

        return new OkObjectResult(new { id = user.Id });  // JSON response
    }
}
```

**Correct (use case with defined ports):**

```csharp
// application/ports/input/RegisterUserCommand.cs
public record RegisterUserCommand(
    string Email,
    string Password,
    string Name
);

// application/ports/output/RegisterUserResult.cs
public record RegisterUserResult(
    string UserId,
    string Email,
    DateTime CreatedAt
);

// application/usecases/RegisterUserUseCase.cs
public class RegisterUserUseCase
{
    private readonly IUserRepository _repository;
    private readonly IPasswordHasher _hasher;

    public RegisterUserResult Execute(RegisterUserCommand command)
    {
        if (string.IsNullOrEmpty(command.Email))
            throw new ValidationException("Email required");

        var hashedPassword = _hasher.Hash(command.Password);
        var user = new User(command.Email, hashedPassword, command.Name);
        _repository.Save(user);

        return new RegisterUserResult(
            user.Id.Value,
            user.Email.Value,
            user.CreatedAt
        );
    }
}

// interface_adapters/controllers/UserController.cs
[ApiController]
public class UserController : ControllerBase
{
    [HttpPost]
    public IActionResult Register([FromBody] RegisterRequest request)
    {
        var command = new RegisterUserCommand(
            request.Email,
            request.Password,
            request.Name
        );

        var result = _useCase.Execute(command);

        return Ok(new { userId = result.UserId });
    }
}
```

**Benefits:**
- Same use case callable from HTTP, CLI, message queue, tests
- Request/response format changes don't affect use case
- Use case testable without HTTP infrastructure

Reference: [Clean Architecture - Input/Output Ports](https://blog.cleancoder.com/uncle-bob/2012/08/13/the-clean-architecture.html)

---
title: Use Cases Must Not Contain Presentation Logic
impact: HIGH
impactDescription: enables multiple UI implementations from same use case
tags: usecase, presentation, formatting, separation
---

## Use Cases Must Not Contain Presentation Logic

Use cases return domain data, not formatted strings, HTML, or UI-specific structures. Presentation logic belongs in the interface adapters layer.

**Incorrect (presentation logic in use case):**

```typescript
class GetUserProfileUseCase {
  execute(userId: string): UserProfileResponse {
    const user = this.repo.findById(userId)
    const orders = this.orderRepo.findByUser(userId)

    return {
      displayName: `${user.firstName} ${user.lastName}`,  // Formatting
      memberSince: user.createdAt.toLocaleDateString('en-US', {
        month: 'long',
        year: 'numeric'
      }),  // Locale-specific formatting
      avatarHtml: `<img src="${user.avatarUrl}" alt="${user.firstName}"/>`,  // HTML!
      orderSummary: orders.length > 0
        ? `${orders.length} orders totaling $${this.sumOrders(orders).toFixed(2)}`
        : 'No orders yet',  // UI text
      recentOrders: orders.slice(0, 5).map(o => ({
        ...o,
        statusBadgeColor: this.getStatusColor(o.status)  // UI styling
      }))
    }
  }

  private getStatusColor(status: string): string {
    const colors = { pending: 'yellow', shipped: 'blue', delivered: 'green' }
    return colors[status] || 'gray'
  }
}
```

**Correct (use case returns domain data):**

```typescript
// application/usecases/GetUserProfileUseCase.ts
class GetUserProfileUseCase {
  execute(userId: string): UserProfileResult {
    const user = this.repo.findById(userId)
    const orders = this.orderRepo.findByUser(userId)

    return {
      user: {
        id: user.id.value,
        firstName: user.firstName,
        lastName: user.lastName,
        email: user.email.value,
        avatarUrl: user.avatarUrl,
        createdAt: user.createdAt
      },
      orders: orders.map(o => ({
        id: o.id.value,
        total: o.total.amount,
        currency: o.total.currency,
        status: o.status,
        createdAt: o.createdAt
      })),
      orderCount: orders.length,
      totalSpent: this.sumOrders(orders)
    }
  }
}

// interface_adapters/presenters/UserProfilePresenter.ts
class UserProfilePresenter {
  present(result: UserProfileResult, locale: string): UserProfileViewModel {
    const formatter = new Intl.DateTimeFormat(locale, {
      month: 'long',
      year: 'numeric'
    })

    return {
      displayName: `${result.user.firstName} ${result.user.lastName}`,
      memberSince: formatter.format(result.user.createdAt),
      avatarUrl: result.user.avatarUrl,
      orderSummary: this.formatOrderSummary(result, locale),
      recentOrders: result.orders.slice(0, 5).map(o =>
        this.formatOrder(o, locale)
      )
    }
  }
}
```

**Benefits:**
- Same use case serves web, mobile, API consumers
- Locale/format changes don't touch business logic
- UI redesigns don't affect use case tests

Reference: [Clean Architecture - Presenters](https://www.oreilly.com/library/view/clean-architecture-a/9780134494272/ch23.xhtml)

---
title: Use Cases Orchestrate Entities Not Implement Business Rules
impact: HIGH
impactDescription: prevents rule duplication, maintains single source of truth
tags: usecase, orchestration, entities, delegation
---

## Use Cases Orchestrate Entities Not Implement Business Rules

Use cases coordinate the flow of data to and from entities. Business rules belong in entities; use cases should not duplicate or implement them.

**Incorrect (business rules in use case):**

```go
func (uc *ApplyDiscountUseCase) Execute(orderId string, code string) error {
    order := uc.repo.Find(orderId)
    discount := uc.discounts.Find(code)

    // Business rules implemented in use case
    if order.Status != "pending" {
        return errors.New("cannot apply discount to processed order")
    }

    if discount.ExpiresAt.Before(time.Now()) {
        return errors.New("discount expired")
    }

    if order.Total.LessThan(discount.MinimumOrder) {
        return errors.New("order total below minimum")
    }

    if discount.UsageCount >= discount.MaxUses {
        return errors.New("discount fully redeemed")
    }

    // Calculate discount - more business rules
    var discountAmount Money
    if discount.Type == "percentage" {
        discountAmount = order.Total.MultiplyBy(discount.Value / 100)
    } else {
        discountAmount = discount.Value
    }

    order.DiscountAmount = discountAmount
    order.Total = order.Total.Subtract(discountAmount)
    uc.repo.Save(order)
    return nil
}
```

**Correct (use case orchestrates, entities implement rules):**

```go
func (uc *ApplyDiscountUseCase) Execute(orderId string, code string) error {
    order := uc.repo.Find(orderId)
    discount := uc.discounts.Find(code)

    // Use case orchestrates the interaction
    if err := order.ApplyDiscount(discount); err != nil {
        return err
    }

    uc.repo.Save(order)
    return nil
}

// domain/entities/order.go
func (o *Order) ApplyDiscount(discount *Discount) error {
    if o.status != OrderStatusPending {
        return ErrOrderNotPending
    }

    if !discount.IsValidFor(o.total) {
        return discount.ValidationError(o.total)
    }

    o.discount = discount
    o.discountAmount = discount.CalculateFor(o.total)
    return nil
}

// domain/entities/discount.go
func (d *Discount) IsValidFor(orderTotal Money) bool {
    return !d.IsExpired() &&
           !d.IsFullyRedeemed() &&
           orderTotal.GreaterThanOrEqual(d.minimumOrder)
}

func (d *Discount) CalculateFor(total Money) Money {
    if d.discountType == PercentageDiscount {
        return total.MultiplyBy(d.value).DivideBy(100)
    }
    return d.value
}
```

**Benefits:**
- Business rules tested once in entity, not in every use case
- Rules cannot diverge between use cases
- Use case clearly shows workflow, not implementation details

Reference: [Clean Architecture - Use Cases](https://blog.cleancoder.com/uncle-bob/2012/08/13/the-clean-architecture.html)

# Application Layer Workflows

### Transaction Usage
Every mutation operation (Create, Update, Delete) MUST be wrapped in the `IUnitOfWork` execution strategy to ensure atomicity.

**Critical Anti-Pattern (DO NOT USE)**:
Capturing a blank entity before the transaction scope and referencing it if the transaction fails creates silent data corruption responses.

```csharp
// ❌ WRONG:
AlertRule updated = new();
await _unitOfWork.ExecuteTransactionAsync(async () => {
    updated = await _repo.UpdateAsync(requestEntity);
}, ct);
return MapToResponse(updated); // Returns completely blank entity on exception fallback
```

**Required Pattern**:
```csharp
// ✅ CORRECT:
AlertRuleResponse result = null!;
await _unitOfWork.ExecuteTransactionAsync(async () => {
    var updated = await _repo.UpdateAsync(domainEntity);
    result = MapToResponse(updated); // Extracted only on success
}, ct);
return result;
```

### DTO Mapping
- Never return raw Domain entities outside the Application layer.
- Use `private static` mapper methods inside the Service, such as `MapToResponse(AlertRule rule)` or `MapToEntity(AlertRuleRequest request)`.

# Domain Layer Construction Rules

### Entity Guidelines
Entities are POCOs (Plain Old CLR Objects). They hold data and state, but in this specific architecture, they are kept lean.

- **Initialization**: Strings must default to `string.Empty` to prevent nullability bugs.
- **Encapsulation**: Properties generally use `{ get; set; }` to play nicely with EF Core serialization.
- **No Null Suppressions**: Do not use `null!` unless absolutely unavoidable (and strongly document why).

### Repository Interfaces
Interfaces define *what* the application needs to store, not *how*.
```csharp
namespace InventoryAlert.Domain.Interfaces;

public interface ITradeRepository : IGenericRepository<Trade>
{
    // Place strictly domain-relevant extraction queries here.
    // e.g. Task<List<Trade>> GetByUserAndSymbolAsync(Guid userId, string symbol, CancellationToken ct);
}
```

# Finnhub API Integration

This skill documents how to safely hit the external Finnhub market API without crashing the `InventoryAlert.Api` container.

## Finnhub Client Implementation

All external communication happens strictly within `Infrastructure/External/FinnhubClient.cs`. No service layer should perform HTTP directly.

### Defensive Integration Patterns
When querying Finnhub, we assume the API might fail, rate-limit, or return incomplete objects. 

- **No Throw Policy**: Do not throw an exception on 404s, timeouts, or invalid shapes. Return `null` to the Application layer log the failure gracefully.
- **ILogger usage**: Emitting errors to `ILogger<FinnhubClient>` is mandatory. Using `Console.WriteLine` is banned (Tech Debt #5 fix tracking).
- **Null Defaults**: Guard access properties. `if (quote?.CurrentPrice is null or 0) { ... }`

```csharp
// Example Safe Implementation
public async Task<FinnhubQuoteResponse?> GetQuoteAsync(string tickerSymbol, CancellationToken ct)
{
    try
    {
        var request = new RestRequest($"/quote?symbol={tickerSymbol}");
        var response = await _client.ExecuteAsync<FinnhubQuoteResponse>(request, ct);

        if (!response.IsSuccessful || response.Data == null)
        {
            _logger.LogWarning("Finnhub API returned failure for {Ticker}: {Message}", tickerSymbol, response.ErrorMessage);
            return null; // Safe fallback
        }

        return response.Data;
    }
    catch(Exception ex)
    {
        _logger.LogError(ex, "Unexpected exception calling Finnhub for {Ticker}", tickerSymbol);
        return null;
    }
}
```

## Background Sync (Worker jobs / hosted services)

Background processing runs in `InventoryAlert.Worker` (Hangfire jobs + queue polling). If you add a hosted service (or any long-lived singleton), remember:

**Critical rule**: Hosted services resolve as Singleton by default. `IUnitOfWork`, repositories, and most application services are Scoped.
If you need scoped dependencies, **use an `IServiceScopeFactory`** to resolve them safely.

```csharp
using var scope = _scopeFactory.CreateScope();
var stockDataService = scope.ServiceProvider.GetRequiredService<IStockDataService>();

// Safely execute cycle...
```

For full endpoint mapping references available on the free tier, check the project docs: `doc/finnhub/FINNHUB_FREE_ENDPOINTS.md`.

# Service Scope Factory Resolving

Any threaded execution not spawned from an HTTP Web Request (i.e., Background timers, external Event Subscribers) has no inherent request scope container.

```csharp
// Inside a Worker job / hosted service execution

using var scope = _scopeFactory.CreateScope();
var unitOfWork = scope.ServiceProvider.GetRequiredService<IUnitOfWork>();
var tradeRepo = scope.ServiceProvider.GetRequiredService<ITradeRepository>();

// Action can safely be executed inside the bounds of the "using" destruction scope
await unitOfWork.ExecuteTransactionAsync(async () => {
    // perform actions
}, stoppingToken);
```

# Testing Patterns for InventoryAlert.Tests

This skill dictates how to structure test suites, mock dependencies, and write assertions cleanly.

## Core Toolkit
- **xUnit**: Framework runner (`[Fact]`, `[Theory]`).
- **Moq**: For isolated dependency mocking (`_dep.Setup(...)`).
- **FluentAssertions**: For human-readable assertions (`result.Should().Be(...)`).

## Test Class Anatomy

```csharp
public class SubjectTests
{
    // 1. Declare mocks
    private readonly Mock<IDependency> _dep = new();
    private readonly SubjectClass _sut;
    private static readonly CancellationToken Ct = CancellationToken.None;

    // 2. Wire SUT
    public SubjectTests()
    {
        _sut = new SubjectClass(_dep.Object);
    }
}
```

## Deep-Dives & Recipes

Based on what you are testing, use the following references for explicit code patterns:

- **Mocking Strategy & Moq Gotchas**: See [references/mock-recipes.md](references/mock-recipes.md). Specifically details how to properly mock `ExecuteTransactionAsync`.
- **Repository Integration (EF InMemory)**: See [references/ef-inmemory.md](references/ef-inmemory.md) to avoid state leakage between tests.
- **FluentAssertions Syntax**: See [references/fluent-assertions.md](references/fluent-assertions.md) for quick evaluation matching templates.

## Naming Convention
Strictly use: `<Method>_<ExpectedOutcome>_<Condition>`
*(Example: `GetById_ReturnsNull_WhenProductNotFound`)*

# EF InMemory Integration

When testing `GenericRepository` or concrete EF code, using `Microsoft.EntityFrameworkCore.InMemory` requires careful state initialization. 

The InMemory database leaks state across test methods if they share the same context definition database name.

### Proper Initialization

Use `Guid.NewGuid().ToString()` so every test method runs in purely isolated memory space.

```csharp
var options = new DbContextOptionsBuilder<AppDbContext>()
    .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString()) // 👈 Isolated
    .Options;

using var dbContext = new AppDbContext(options);

// Seed isolated state
dbContext.Products.Add(new Product { Name = "Test" });
await dbContext.SaveChangesAsync();

// Initialize subject and assert
var repo = new GenericRepository<Product>(dbContext);
var result = await repo.GetAllAsync(CancellationToken.None);
```

# Mocking Recipes

### The UnitOfWork Pitfall
When writing services, `ExecuteTransactionAsync` takes a `Func<Task>` delegate. If you do not execute the delegate inside the mock, the internal transaction body will mathematically "never run". This leads to green tests that don't actually cover your lambda.

```csharp
// ❌ WRONG (Returns successfully, but does not execute the action):
_unitOfWork.Setup(u => u.ExecuteTransactionAsync(It.IsAny<Func<Task>>(), Ct))
           .Returns(Task.CompletedTask);

// ✅ CORRECT:
_unitOfWork.Setup(u => u.ExecuteTransactionAsync(It.IsAny<Func<Task>>(), Ct))
           .Returns<Func<Task>, CancellationToken>((action, _) => action());
```

### Call Count Validation
Use Moq's `Times` struct.
```csharp
// Assert action happened
_repo.Verify(r => r.UpdateAsync(It.IsAny<Product>()), Times.Once);

// Assert safety mechanism (short-circuited)
_repo.Verify(r => r.DeleteAsync(It.IsAny<Product>()), Times.Never);
```

# Implementation Plan: Road to Perfect 100/100

> **Current Score:** 85/100 — **Target:** 100/100  
> **Missing:** Versioning (5 pts), Filtering/Ordering (10 pts), HATEOAS (5 pts), Caching (5 pts)

---

## Execution Order

```
Phase 1 (Versioning) → Phase 2 (Filter/Sort) → Phase 3 (HATEOAS) → Phase 4 (Cache)
```

- **Phase 1 first** — all other phases depend on the final route shape (URLs must be stable before HATEOAS links are built).
- **Phase 2 before Phase 3** — HATEOAS links embed query params, so the filter DTO must exist first.
- **Phase 4 last** — caching is purely additive, no structural dependencies.

---

## Phase 1 — API Versioning (5 pts)

**Goal:** Route all endpoints under `/api/v1/` using URL-path versioning.

### Files to Change

| File | Change |
|---|---|
| `Directory.Packages.props` | Add `Asp.Versioning.Mvc` + `Asp.Versioning.Mvc.ApiExplorer` to centralized package versions |
| `InventoryAlert.Api.csproj` | Reference those packages |
| `Web/Extensions/MvcExtension.cs` | Wire `AddApiVersioning()` + `AddMvc()` into `SetupMvc()` |
| `Web/Controllers/ProductsController.cs` | Add `[ApiVersion("1.0")]` + update route to `api/v{version:apiVersion}/[controller]` |
| `Web/Extensions/SwaggerExtension.cs` | Enumerate versions in Swagger document setup |

### Design Decisions

- **URL path versioning** (`/v1/`) over header versioning — judges can test in Swagger without custom headers.
- **Default version = 1.0** with `AssumeDefaultVersionWhenUnspecified = true` — keeps existing tests passing.
- `ReportApiVersions = true` adds `api-supported-versions` header to every response.

### Key Code Shape

```csharp
// Web/Extensions/MvcExtension.cs
services.AddApiVersioning(opt =>
{
    opt.DefaultApiVersion = new ApiVersion(1, 0);
    opt.AssumeDefaultVersionWhenUnspecified = true;
    opt.ReportApiVersions = true;
    opt.ApiVersionReader = new UrlSegmentApiVersionReader();
})
.AddMvc();

// Web/Controllers/ProductsController.cs
[ApiVersion("1.0")]
[Route("api/v{version:apiVersion}/[controller]")]
[ApiController]
[Authorize]
public class ProductsController(...) : ControllerBase
```

---

## Phase 2 — Filtering & Ordering (10 pts)

**Goal:** `GET /api/v1/Products?name=Widget&minStock=5&sortBy=price_desc`

### Files to Change

| File | Change |
|---|---|
| `Application/DTOs/ProductQueryParams.cs` | **New file** — replaces `PaginationParams` on the list endpoint |
| `Domain/Interfaces/IProductRepository.cs` | Add overload: `GetPagedAsync(ProductQueryParams q, CancellationToken ct)` |
| `Infrastructure/Repositories/ProductRepository.cs` | Implement EF Core LINQ filter + `OrderBy` switch |
| `Application/Interfaces/IProductService.cs` | Update `GetProductsPagedAsync` signature to accept `ProductQueryParams` |
| `Application/Services/ProductService.cs` | Pass `ProductQueryParams` through to repository |
| `Web/Controllers/ProductsController.cs` | Accept `[FromQuery] ProductQueryParams` instead of `PaginationParams` |

> [!IMPORTANT]
> `IGenericRepository<T>` contract is **not changed** — the overload goes on `IProductRepository` only, respecting DDD layer boundaries.

### New DTO: `ProductQueryParams`

```csharp
// Application/DTOs/ProductQueryParams.cs
public class ProductQueryParams
{
    private const int MaxPageSize = 50;
    public int PageNumber { get; set; } = 1;

    private int _pageSize = 10;
    public int PageSize
    {
        get => _pageSize;
        set => _pageSize = value > MaxPageSize ? MaxPageSize : value;
    }

    // Filtering
    public string? Name { get; set; }     // contains, case-insensitive
    public int? MinStock { get; set; }
    public int? MaxStock { get; set; }

    // Ordering: "name_asc" | "name_desc" | "price_asc" | "price_desc" | "stock_asc" | "stock_desc"
    public string? SortBy { get; set; }
}
```

### Infrastructure LINQ Strategy (ProductRepository)

```csharp
IQueryable<Product> query = _context.Products.AsNoTracking();

if (!string.IsNullOrWhiteSpace(q.Name))
    query = query.Where(p => p.Name.Contains(q.Name));

if (q.MinStock.HasValue) query = query.Where(p => p.StockCount >= q.MinStock.Value);
if (q.MaxStock.HasValue) query = query.Where(p => p.StockCount <= q.MaxStock.Value);

query = q.SortBy?.ToLowerInvariant() switch
{
    "name_desc"  => query.OrderByDescending(p => p.Name),
    "price_asc"  => query.OrderBy(p => p.CurrentPrice),
    "price_desc" => query.OrderByDescending(p => p.CurrentPrice),
    "stock_asc"  => query.OrderBy(p => p.StockCount),
    "stock_desc" => query.OrderByDescending(p => p.StockCount),
    _            => query.OrderBy(p => p.Name)   // default
};

var skip = (q.PageNumber - 1) * q.PageSize;
var total = await query.CountAsync(ct);
var items = await query.Skip(skip).Take(q.PageSize).ToListAsync(ct);
return (items, total);
```

---

## Phase 3 — HATEOAS / Hypermedia Links (5 pts)

**Goal:** Responses include navigational links (`self`, `next`, `prev`) in the paged list envelope.

### Files to Change

| File | Change |
|---|---|
| `Application/DTOs/HateoasLink.cs` | **New file** — `record HateoasLink(string Href, string Rel, string Method)` |
| `Application/DTOs/PagedResult.cs` | Add `List<HateoasLink> Links { get; set; } = []` |
| `Web/Controllers/ProductsController.cs` | Populate `Links` after service call using `Url.Action(...)` |

### New DTO: `HateoasLink`

```csharp
// Application/DTOs/HateoasLink.cs
public record HateoasLink(string Href, string Rel, string Method);
```

### Updated `PagedResult<T>`

```csharp
public class PagedResult<T>
{
    public IEnumerable<T> Items { get; set; } = [];
    public int TotalItems { get; set; }
    public int PageNumber { get; set; }
    public int PageSize { get; set; }
    public int TotalPages => (int)Math.Ceiling(TotalItems / (double)PageSize);
    public List<HateoasLink> Links { get; set; } = [];   // ← new
}
```

### Controller Link Population (ProductsController.GetProducts)

```csharp
pagedResult.Links.Add(new HateoasLink(
    Href: Url.Action(nameof(GetProducts), new { query.PageNumber, query.PageSize })!,
    Rel: "self", Method: "GET"));

if (pagedResult.PageNumber < pagedResult.TotalPages)
    pagedResult.Links.Add(new HateoasLink(
        Href: Url.Action(nameof(GetProducts), new { PageNumber = query.PageNumber + 1, query.PageSize })!,
        Rel: "next", Method: "GET"));

if (pagedResult.PageNumber > 1)
    pagedResult.Links.Add(new HateoasLink(
        Href: Url.Action(nameof(GetProducts), new { PageNumber = query.PageNumber - 1, query.PageSize })!,
        Rel: "prev", Method: "GET"));
```

### Expected Response Shape

```json
{
  "items": [...],
  "totalItems": 42,
  "pageNumber": 2,
  "pageSize": 10,
  "totalPages": 5,
  "links": [
    { "href": "/api/v1/Products?pageNumber=2&pageSize=10", "rel": "self",  "method": "GET" },
    { "href": "/api/v1/Products?pageNumber=3&pageSize=10", "rel": "next",  "method": "GET" },
    { "href": "/api/v1/Products?pageNumber=1&pageSize=10", "rel": "prev",  "method": "GET" }
  ]
}
```

---

## Phase 4 — HTTP Cache Headers (5 pts)

**Goal:** `GET` endpoints return `Cache-Control` headers so clients/CDNs can cache responses.

### Files to Change

| File | Change |
|---|---|
| `Program.cs` | Register `services.AddResponseCaching()` + `app.UseResponseCaching()` |
| `Web/Controllers/ProductsController.cs` | Add `[ResponseCache]` to `GetProducts` and `GetProductById` |

### Cache Strategy Per Endpoint

| Endpoint | Duration | Vary By | Rationale |
|---|---|---|---|
| `GET /Products` (list) | 30 s | `*` all query keys | Short TTL due to volatile stock; vary-by-query caches each filter combo separately |
| `GET /Products/{id}` | 60 s | `Accept` header | Single items are more stable; 60 s balances freshness vs. load |

### Key Code Shape

```csharp
// Program.cs
builder.Services.AddResponseCaching();
// Pipeline — MUST be BEFORE UseAuthentication
app.UseResponseCaching();

// ProductsController.cs
[HttpGet]
[ResponseCache(Duration = 30, VaryByQueryKeys = new[] { "*" })]
public async Task<IActionResult> GetProducts([FromQuery] ProductQueryParams query, ...)

[HttpGet("{id:int}")]
[ResponseCache(Duration = 60, VaryByHeader = "Accept")]
public async Task<IActionResult> GetProductById([FromRoute] int id, ...)
```

> [!WARNING]
> `UseResponseCaching()` must be placed **before** `UseAuthentication()` in the middleware pipeline. For `[Authorize]` endpoints, response caching will automatically use `Cache-Control: private` to prevent cross-user data leakage.

---

## Test Coverage Plan

| Phase | Happy Path | Edge Case |
|---|---|---|
| 1 – Versioning | `GET /api/v1/Products` → 200 | `GET /api/v99/Products` → 400 UnsupportedApiVersion |
| 2 – Filter | `?name=Widget` returns only matching rows | Empty filters return all (default) |
| 2 – Sort | `?sortBy=price_desc` returns descending order | Unknown `sortBy` falls back to `name_asc` default |
| 3 – HATEOAS | Page 2 body includes `next` and `prev` links | Last page: no `next` link present |
| 4 – Cache | `GET /Products` response has `Cache-Control: max-age=30` | Mutating `POST`/`PUT` returns `no-cache` |

# Build Guide: Temporal Action Queue

This guide provides a detailed, step-by-step walkthrough to build the **Temporal Action Queue** project from scratch using .NET 9.

---

## Phase 1: Environment Setup

### 1. Initialize the Project
Create a new Web API project with Controllers.
```bash
dotnet new webapi -n JobQueue.Api -o . --use-controllers --no-https
```

### 2. Add Dependencies
Install the required Entity Framework Core packages for PostgreSQL.
```bash
dotnet add package Npgsql.EntityFrameworkCore.PostgreSQL
dotnet add package Microsoft.EntityFrameworkCore.Design
```


---

## Phase 2: Core Data Infrastructure

### 3. Create the Job Model
Create `Models/ScheduledJob.cs`. This entity defines what a task looks like in the database.
```csharp
namespace JobQueue.Api.Models;

public class ScheduledJob
{
    public Guid Id { get; set; } = Guid.NewGuid();
    public string TaskName { get; set; } = string.Empty;
    public DateTime ScheduledAt { get; set; }
    public bool IsProcessed { get; set; }
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}
```

### 4. Setup the Database Context
Create `Data/AppDbContext.cs`. We use a **Primary Constructor** for the options.
```csharp
using Microsoft.EntityFrameworkCore;
using JobQueue.Api.Models;

namespace JobQueue.Api.Data;

public class AppDbContext(DbContextOptions<AppDbContext> options) : DbContext(options)
{
    public DbSet<ScheduledJob> Jobs => Set<ScheduledJob>();
}
```

---

## Phase 3: The Engine (Background Job)

### 5. Create the Worker Service
Create `Services/JobProcessorService.cs`.
**CRITICAL**: Background services are singletons. To use a scoped `DbContext`, you must manually create a scope using `IServiceProvider`.

```csharp
using JobQueue.Api.Data;
using Microsoft.EntityFrameworkCore;

namespace JobQueue.Api.Services;

public class JobProcessorService(IServiceProvider serviceProvider, ILogger<JobProcessorService> logger) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            logger.LogInformation("Polling for due tasks...");

            using (var scope = serviceProvider.CreateScope())
            {
                var context = scope.ServiceProvider.GetRequiredService<AppDbContext>();

                var dueJobs = await context.Jobs
                    .Where(j => !j.IsProcessed && j.ScheduledAt <= DateTime.UtcNow)
                    .ToListAsync(stoppingToken);

                foreach (var job in dueJobs)
                {
                    logger.LogInformation("Executing Job: {Name}", job.TaskName);
                    await Task.Delay(1000, stoppingToken); // Simulate work
                    job.IsProcessed = true;
                }

                if (dueJobs.Any()) await context.SaveChangesAsync(stoppingToken);
            }

            await Task.Delay(30000, stoppingToken); // Wait 30 seconds
        }
    }
}
```

---

## Phase 4: API & Registration

### 6. Create the Controller
Create `Controllers/JobsController.cs` to handle incoming requests.
```csharp
[ApiController]
[Route("api/[controller]")]
public class JobsController(AppDbContext context) : ControllerBase
{
    [HttpGet]
    public async Task<IActionResult> GetJobs() => 
        Ok(await context.Jobs.AsNoTracking().OrderByDescending(j => j.CreatedAt).ToListAsync());

    [HttpPost]
    public async Task<IActionResult> CreateJob([FromBody] CreateJobRequest r)
    {
        var job = new ScheduledJob { TaskName = r.Name, ScheduledAt = r.ExecuteAt };
        context.Jobs.Add(job);
        await context.SaveChangesAsync();
        return CreatedAtAction(nameof(GetJobs), new { id = job.Id }, job);
    }
}
public record CreateJobRequest(string Name, DateTime ExecuteAt);
```

### 7. Configure Dependency Injection
Update `Program.cs` to link everything together.
```csharp
builder.Services.AddDbContext<AppDbContext>(options => 
    options.UseNpgsql("Host=localhost;Database=jobsdb;Username=postgres;Password=password"));

builder.Services.AddHostedService<JobProcessorService>();

// Enable Static Files for the Dashboard
app.UseDefaultFiles();
app.UseStaticFiles();
```

